p.m:
\displaystyle{\begin{aligned}
   {\frac{\frac{2}{t}+\frac{8}{y}}{\frac{10}{t}-\frac{2}{y}}} 
      \amp = {\frac{\frac{2}{t}+\frac{8}{y}}{\frac{10}{t}-\frac{2}{y}}} \cdot \frac{{ty}}{{ty}} \\
      \amp = {\frac{\left(\frac{2}{t}+\frac{8}{y}\right)ty}{\left(\frac{10}{t}-\frac{2}{y}\right)ty}} \\
      \amp = \frac{\frac{2}{t} \cdot t y +\frac{8}{y} \cdot t y }{\frac{10}{t} \cdot t y  - \frac{2}{y} \cdot t y } \\
      \amp = \frac{2 y + 8 t}{10 y - 2 t} \\
      \amp = {\frac{2\mathopen{}\left(y+4t\right)}{2\mathopen{}\left(5y-t\right)}} \\
      \amp = {\frac{y+4t}{5y-t}}
\end{aligned}
    }
